import java.io.File

class AwsService {

  private val credentialsProvider: AWSCredentialsProvider = DefaultAWSCredentialsProviderChain.getInstance()
  private val s3Client: AmazonS3 = AmazonS3ClientBuilder.standard()
    .withCredentials(credentialsProvider)
    .withRegion("us-west-2") // Replace with your region
